        x.mincnt = a.mincnt + b.mincnt;
        x.minval = a.minval;
    } else if (a.minval < b.minval) {
        x.mincnt = a.mincnt;
        x.minval = a.minval;
    } else {
        x.mincnt = b.mincnt;
        x.minval = b.minval;
    }
}
void refresh(int x) {
    merge(segs[x], segs[x << 1], segs[x << 1 | 1]);
}
void tag_add(int x, int v) {
    segs[x].minval += v;
    segs[x].atag += v;
}
void pushdown(int x) {
    if (segs[x].atag) {
        tag_add(x << 1, segs[x].atag);
        tag_add(x << 1 | 1, segs[x].atag);
        segs[x].atag = 0;
    }
}
void rangeadd(int x, int l, int r, int al, int ar, int v) {
    if (al <= l && ar >= r) {
        tag_add(x, v);
        return;
    }
    pushdown(x);
    int mid = (l + r) >> 1;
    if (al <= mid)
        rangeadd(x << 1, l, mid, al, ar, v);
    if (ar > mid)
        rangeadd(x << 1 | 1, mid + 1, r, al, ar, v);
    refresh(x);
}
Seg query(int x, int l, int r, int ql, int qr) {
    if (ql <= l && qr >= r) {
        return segs[x];
    }
    pushdown(x);
    int mid = (l + r) >> 1;
    Seg ans = (Seg){INF, 0, 0};
    if (ql <= mid)
        merge(ans, ans, query(x << 1, l, mid, ql, qr));
    if (qr > mid)
        merge(ans, ans, query(x << 1 | 1, mid + 1, r, ql, qr));
    return ans;
}
int ves[N];
int dfn[N], arr[N], siz[N], dcnt;
bool onpath[N];
void dfs(int u, int f) {
    dfn[u] = ++dcnt;
    arr[dcnt] = u;
    siz[u] = 1;
    ves[u] = ves[f] + 1;
    onpath[u] = true;
    for (int v : bt.sons[u]) {
        if (onpath[v]) {
            ves[u]--;
        }
    }
    for (int v : at.sons[u]) {
        if (v == f)
            continue;
        dfs(v, u);
        siz[u] += siz[v];
    }
    onpath[u] = false;
}
void build(int x, int l, int r) {
    if (l == r) {
        segs[x].mincnt = 1;
        segs[x].atag = 0;
        segs[x].minval = ves[arr[l]];
        return;
    }
    int mid = (l + r) >> 1;
    build(x << 1, l, mid);
    build(x << 1 | 1, mid + 1, r);
    refresh(x);
}
bool cmp(int a, int b) {
    return dfn[a] < dfn[b];
}
bool in(int a, int b) {
    return dfn[b] >= dfn[a] && dfn[b] < dfn[a] + siz[a];
}
void treeadd(int u, int v) {
    rangeadd(1, 1, dcnt, dfn[u], dfn[u] + siz[u] - 1, v);
}
void out() {
    for (int i = 1; i <= dcnt; i++) {
        cout << query(1, 1, dcnt, i, i).minval << " ";
    }
    cout << endl;
}

int moveRoot(int u, int v, int x, int bi) {
    treeadd(v, -1 * x);  // v子树内的点少了u
    //删除u的边
    while (bi < bt.sons[u].size() && dfn[bt.sons[u][bi]] < dfn[v] + siz[v]) {
        if (dfn[bt.sons[u][bi]] >= dfn[v])
            treeadd(bt.sons[u][bi], 1 * x);
        bi++;
    }

    treeadd(1, 1 * x);  // v子树外的点多了v
    treeadd(v, -1 * x);
    //增加v的边
    for (int w : bt.sons[v]) {
        if (in(v, w))
            continue;
        if (u == w) {
            treeadd(v, 1 * x);
            treeadd(1, -1 * x);
        } else if (in(w, u)) {
            int l = 0, r = at.sons[w].size() - 1;
            while (l < r) {
                int mid = (l + r + 1) >> 1;
                if (dfn[at.sons[w][mid]] <= dfn[u]) {
                    l = mid;
                } else {
                    r = mid - 1;
                }
            }
            int t = at.sons[w][l];
            treeadd(t, 1 * x);
            treeadd(1, -1 * x);
        } else {
            treeadd(w, -1 * x);
        }
    }
    return bi;
}
int ans = 0;
void solve(int u, int f) {
    ans += query(1, 1, dcnt, 1, dcnt).mincnt;
    sort(at.sons[u].begin(), at.sons[u].end(), cmp);
    sort(bt.sons[u].begin(), bt.sons[u].end(), cmp);
    int bi = 0;
    for (int v : at.sons[u]) {
        if (v == f)
            continue;
        moveRoot(u, v, 1, bi);
        solve(v, u);
        bi = moveRoot(u, v, -1, bi);
    }
}
void test() {
    memset(segs,0,sizeof(segs));
    ans = 0;
    dcnt = 0;
    int n;
    cin >> n;
    for (int i = 1; i < n; i++) {
        int u, v;
        cin >> u >> v;
        bt.add_edge(u, v);
        bt.add_edge(v, u);
    }
    for (int i = 1; i < n; i++) {
        int u, v;
        cin >> u >> v;
        at.add_edge(u, v);
        at.add_edge(v, u);
    }
    dfs(1, 0);
    build(1, 1, dcnt);
    solve(1, 0);
    cout << (ans - n) / 2 + n << endl;
    at.clear(n);
    bt.clear(n);
}
int main() {
    int t;
    cin >> t;
    while (t--) {
        test();
    }
}
```

#### 完整解法二 -- 点分治

仍然考虑个链的做法拓展到树上,在A树进行点分治,首先对于每一层:

- 预处理分治的当前层中所有节点到重心的链在B树上的$V-E$,此时可以顺便把从一个端点在根的路径的答案求出,于是后面仅考虑两端点在不同子树的,也就是说,当处理一棵子树时子树内的点答案正确性无需考虑.
- 按dfs序递增的遍历根在A树上所有儿子,此时遍历到一个点时,维护的$V-E$就是所有点到分治中心的链的值,dfs当前儿子的子树,进入一个点时把答案移动成所有点到当前点的$V-E$,所以就是
  - 给当前子树外的所有点+1
  - 遍历它每一条边,判断这条边是指向节点(设为 w )在当前处理的子树外还是当前节点到根的路径上:
    - 子树外:给 w 的子树-1
    - 子树内到根的路径上:因为我们已经只考虑跨子树的路径,所以只要给当前子树外的点-1即可.

注意每做完一棵子树清空.

