- 强联通分量

  - 条件:dfs时八店入栈,在dfn\[u\]=low\[v\]时,要退出dfs时若满足条件一直弹栈到把自己也弹了,弹出部分都是同一scc
  - 理解:同一强联通分量在dfs中是连续的一块,在栈里也是
  - 细节:low不更新横叉边指向的点(已经被访问却在栈外)

### 差分约束

#### 细节:

1. 最短路是满足条件的最大解,最长路是最小解

2. 建立隐藏条件边

3. 相等条件双向连边

## 字符串

### SAM

```cpp
const int N=1e6+500;
struct node{
    int nxt[27];
    int len,link;
} ns[N*2];
int root,last,scnt;
void init(){
    root=0;
    ns[0].link=-1;
    ns[0].len=0;
    last=root;
    scnt=0;
}
void insert(char c){
    int cur=++scnt;
    ns[cur].len=ns[last].len+1;
    int p=last;
    last=cur;
    while(p!=-1&&!ns[p].nxt[c]){
        ns[p].nxt[c]=cur;
        p=ns[p].link;
    }
    if(p==-1){
        ns[cur].link=root;
        return;
    }
    int q=ns[p].nxt[c];
    if(ns[p].len+1==ns[q].len){
        ns[cur].link=q;
        return;
    }
    int clone=++scnt;
    ns[clone].len=ns[p].len+1;
    ns[clone].link=ns[q].link;
    memcpy(ns[clone].nxt,ns[q].nxt,sizeof(ns[clone].nxt));
    while(p!=-1&&ns[p].nxt[c]==q){
        ns[p].nxt[c]=clone;
        p=ns[p].link;
    }
    ns[q].link=ns[cur].link=clone;
}
```

#### 细节:

1. 记得初始化
2. 记得p=ns[p].link的挑父亲
3. 记得数组开2倍

## 数据结构

### LCT

```cpp
const int N=1e5+500;
int fa[N],ch[N][2],val[N],xors[N];
bool rev[N];
bool notroot(int x){
    return ch[fa[x]][0]==x||ch[fa[x]][1]==x;
}
bool chk(int x){
    return ch[fa[x]][1]==x;
}
void refresh(int x){
    xors[x]=xors[ch[x][0]]^xors[ch[x][1]]^val[x];
}
void tag_rev(int x){
    swap(ch[x][0],ch[x][1]);
    rev[x]^=1;
}
void pushdown(int x){
    if(!rev[x])return;
    tag_rev(ch[x][0]);
    tag_rev(ch[x][1]);
    rev[x]=false;
}
void rotate(int x){
    int f=fa[x],gf=fa[f],k1=chk(x),k2=chk(f);
    fa[x]=gf;
    if(notroot(f))ch[gf][k2]=x;
    if(ch[x][k1^1])fa[ch[x][k1^1]]=f;
    ch[f][k1]=ch[x][k1^1];
    fa[f]=x;
    ch[x][k1^1]=f;
    refresh(f);
    refresh(x);
}
int stk[N];
void splay(int x){
    int scnt=0,tmp=x;
    while(notroot(tmp)){
        stk[++scnt]=tmp;
        tmp=fa[tmp];
    }
    stk[++scnt]=tmp;
    while(scnt)pushdown(stk[scnt--]);
    while(notroot(x)){
        int f=fa[x];
        if(notroot(f)){
            if(chk(f)==chk(x)){
                rotate(f);
            }else{
                rotate(x);
            }
        }
        rotate(x);
    }
}
void access(int x){
    for(int y=0;x;y=x,x=fa[x]){
        splay(x);
        ch[x][1]=y;
        refresh(x);
    }
}
void changeroot(int x){
    access(x);
    splay(x);
    tag_rev(x);
}
int findroot(int x){
    access(x);
    splay(x);
    pushdown(x);
    while(ch[x][0]){
        x=ch[x][0];
        pushdown(x);
    }
    splay(x);
    return x;
}
void link(int u,int v){
    changeroot(u);
    if(findroot(v)!=u){
        fa[u]=v;
    }
}
void cut(int x,int y){
    changeroot(x);
    if(findroot(y)!=x||fa[y]!=x||ch[y][0])return;
    fa[y]=0;
    ch[x][0]=0;
    refresh(x);
}
void split(int x,int y){
    changeroot(x);
    access(y);
    splay(x);
}
```

#### 细节:

1. 注意findroot最后要splay根

2. cut的判断:findroot(y)==x说明在同一棵树,fa[y]==x是因为直接相连,ch[y][0]==0因为比它浅的只有根,根是它的父亲.

3. access背过

4. findroot要记得pushdown

## 多项式

### FWT

```cpp

void fwtAnd(int *f,int x){
    for(int l=2;l<=n;l<<=1){
        int mid=l>>1;
        for(int p=0;p<n;p+=l){
            for(int k=0;k<mid;k++){
                f[p+k]=(f[p+k]+f[p+k+mid]*x)%P;
            }
        }
    }
}
void fwtOr(int *f,int x){
    for(int l=2;l<=n;l<<=1){
        int mid=l>>1;
        for(int p=0;p<n;p+=l){
            for(int k=0;k<mid;k++){
                f[p+k+mid]=(f[p+k]*x+f[p+k+mid])%P;
            }
        }
    }
}
void fwtXor(int *f,int x){
    for(int l=2;l<=n;l<<=1){
        int mid=l>>1;
        for(int p=0;p<n;p+=l){
            for(int k=0;k<mid;k++){
                int o1=f[p+k],o2=f[p+k+mid];
                f[p+k]=(o1+o2)*x%P;
                f[p+k+mid]=(o1-o2)*x%P;
            }
        }
    }
}
```

别把与和或弄反,亦或最后x是1(正变换)或1/2(逆变换)

输出时要注意把数弄回正的,因为减法过程会出负数

