    int scnt=0,tmp=x;
    while(notroot(tmp)){
        stk[++scnt]=tmp;
        tmp=fa[tmp];
    }
    stk[++scnt]=tmp;
    while(scnt)pushdown(stk[scnt--]);
    while(notroot(x)){
        int f=fa[x];
        if(notroot(f)){
            if(chk(f)==chk(x)){
                rotate(f);
            }else{
                rotate(x);
            }
        }
        rotate(x);
    }
}
void access(int x){
    for(int y=0;x;y=x,x=fa[x]){
        splay(x);
        ch[x][1]=y;
        refresh(x);
    }
}
void changeroot(int x){
    access(x);
    splay(x);
    tag_rev(x);
}
int findroot(int x){
    access(x);
    splay(x);
    pushdown(x);
    while(ch[x][0]){
        x=ch[x][0];
        pushdown(x);
    }
    splay(x);
    return x;
}
void link(int u,int v){
    changeroot(u);
    if(findroot(v)!=u){
        fa[u]=v;
    }
}
void cut(int x,int y){
    changeroot(x);
    if(findroot(y)!=x||fa[y]!=x||ch[y][0])return;
    fa[y]=0;
    ch[x][0]=0;
    refresh(x);
}
void split(int x,int y){
    changeroot(x);
    access(y);
    splay(x);
}
```

#### 细节:

1. 注意findroot最后要splay根

2. cut的判断:findroot(y)==x说明在同一棵树,fa[y]==x是因为直接相连,ch[y][0]==0因为比它浅的只有根,根是它的父亲.

3. access背过

4. findroot要记得pushdown

## 多项式

### FWT

```cpp

void fwtAnd(int *f,int x){
    for(int l=2;l<=n;l<<=1){
        int mid=l>>1;
        for(int p=0;p<n;p+=l){
            for(int k=0;k<mid;k++){
                f[p+k]=(f[p+k]+f[p+k+mid]*x)%P;
            }
        }
    }
}
void fwtOr(int *f,int x){
    for(int l=2;l<=n;l<<=1){
        int mid=l>>1;
        for(int p=0;p<n;p+=l){
            for(int k=0;k<mid;k++){
                f[p+k+mid]=(f[p+k]*x+f[p+k+mid])%P;
            }
        }
    }
}
void fwtXor(int *f,int x){
    for(int l=2;l<=n;l<<=1){
        int mid=l>>1;
        for(int p=0;p<n;p+=l){
            for(int k=0;k<mid;k++){
                int o1=f[p+k],o2=f[p+k+mid];
                f[p+k]=(o1+o2)*x%P;
                f[p+k+mid]=(o1-o2)*x%P;
            }
        }
    }
}
```

别把与和或弄反,亦或最后x是1(正变换)或1/2(逆变换)

输出时要注意把数弄回正的,因为减法过程会出负数

